import ScrollListener from '../shared/scroll-listener.js';const ReadingProgress={progressBar: null,currentProgress: 0,init(){this.createProgressBar();this.bindScroll();},createProgressBar(){if(document.getElementById('reading-progress'))return;this.progressBar=document.createElement('div');this.progressBar.id='reading-progress';this.progressBar.className='reading-progress-bar';this.progressBar.innerHTML='<div class="reading-progress-fill"></div>';document.body.prepend(this.progressBar);},bindScroll(){const onScroll=()=>{const scrollTop=window.scrollY;const docHeight=document.documentElement.scrollHeight-window.innerHeight;const progress=docHeight>0 ?(scrollTop/docHeight)*100 : 0;this.currentProgress=progress;this.update(progress);this.toggleVisibility(scrollTop);};ScrollListener.add('reading-progress',onScroll,{passive: true,debounce: 50});onScroll();},update(progress){if(!this.progressBar)return;const fill=this.progressBar.querySelector('.reading-progress-fill');if(fill){fill.style.width=`${Math.min(100,Math.max(0,progress))}%`;}},toggleVisibility(scrollTop){if(!this.progressBar)return;if(scrollTop<100){this.progressBar.classList.add('hidden');}else{this.progressBar.classList.remove('hidden');}},reset(){this.update(0);},getProgress(){return this.currentProgress;}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>ReadingProgress.init());}else{ReadingProgress.init();}export{ReadingProgress};